"use strict";(self.webpackChunk=self.webpackChunk||[]).push([[95721],{11432(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>o,toc:()=>c});var o=n(76503),i=n(74848),a=n(28453);const s={title:"ContainerCLI: A CLI tool for your Docker Application",author:"Philipp Zehnder",authorURL:"http://twitter.com/philipp10der",authorImageURL:"/img/zehnder.png"},r=void 0,l={authorsImageUrls:[void 0]},c=[];function h(e){const t={a:"a",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:(0,i.jsx)("div",{style:{float:"left",paddingRight:"40px"},children:"6 minutes to read"})})}),"\n",(0,i.jsx)("br",{}),"\n",(0,i.jsx)(t.p,{children:"In this blog post, we show how we developed a CLI tool to install and manage StreamPipes.\nIn addition, we present a template project that enables you to easily create a CLI tool for your own docker application.\nAll you need is a working docker-compose.yml file."}),"\n",(0,i.jsx)(t.p,{children:"StreamPipes has a Microservice architecture and we use Docker and Docker Compose for all of our development, testing, and deployment processes.\nIn the beginning, we developed the CLI only to ease the installation process (e.g. managing multiple versions), but over time we realized that the tool is much more powerful.\nFor example, StreamPipes has multiple developer roles: Some developers are working on the frontend, others on the backend, and some are developing new algorithms and data sinks for StreamPipes.\nIn the figure below, you can see different configurations that are used by different developers.\nAll services are running in docker, except for the ones the developer is currently working on.\nAs a result, we had many different docker-compose.yml files and when we made changes, we had to synchronize them all."}),"\n",(0,i.jsx)("img",{class:"blog-image",style:{maxWidth:"60%"},src:"/img/blog/2018-11-24/roles.png",alt:"Three different developer roles"}),"\n",(0,i.jsxs)(t.p,{children:["Therefore, our goal was to speed up the setup of a development environment, so that developers can focus on their specific programming task.\nThat\u2019s why we developed a command line tool that automates the setup of different environments.\nAll what is needed is a docker-compose.yml file that describes all services of the application and the template CLI project from ",(0,i.jsx)(t.a,{href:"https://github.com/streampipes/container-cli",children:"GitHub"}),".\nAfterwards, you need to split up your compose file and create an individual file for each service. Put those files in individual folders in the services folder.\nEach folder should have the same name as the service name in the docker-compose file. That\u2019s it!\nNow you can use the CLI.\nWith the default commands you are able to start, stop, and configure the application. But how is this better than just using docker itself?\nThe advantage is the flexibility and extensibility of the tool.\nYou can extend the script with tasks you have to perform regularly, like cleaning up volumes, or setting up testing environments."]}),"\n",(0,i.jsxs)(t.p,{children:["In the following we will describe the tool in more detail.\nYou can see all files and folders of the CLI Tool in the next listing.\nThe first file \u201ccontainer-cli.m4\u201d contains the script.\nWe use ",(0,i.jsx)(t.a,{href:"https://argbash.io/",children:"Argbash"}),", which eases the use of bash script parameters and flags.\nIn this file you can easily add new custom commands, flags or other functionalities.\nThe next file is the actual bash script. It is generated by argbash.\nSince this file is generated automatically, you should not change anything.\nThe docker-compose.yml file is the main file.\nThis should contain all services, networks, or volume information that is relevant for all the other services of your application.\nAll your other services are located in the services folder.\nFor each service, create a folder with the name of the service and place a docker-compose.yml in the folder configuring the service.\nTherefore, you can copy and paste the configuration from your current docker-compose.yml.\nThe script checks the services folder dynamically, this means you can add services at a later point in time without changing anything else.\nIn our example, we have four services: Backend, UI, database, and a test database containing data for the end2end tests.\nWhich services should be started when running the command ",(0,i.jsx)(t.strong,{children:'"container-cli start"'})," is defined in the active-service file.\nThis file contains the names of all services, each in one line, that should be started.\nOften it is required to have multiple configurations of your app. You can save them in the templates folder.\nBy running ",(0,i.jsx)(t.strong,{children:"\u201ccontainer-cli set-template ui_developer\u201d"}),", you can select the template ui_developer.\nWith this command, all services defined in the template are written to the active-services file. (e.g. the ui_developer template contains just the database and backend and the e2e-test template contains the backend, ui, and test-database)."]}),"\n",(0,i.jsx)("img",{class:"blog-image",style:{maxWidth:"30%"},src:"/img/blog/2018-11-24/files.png",alt:"Structure of the containter cli project"}),"\n",(0,i.jsx)(t.p,{children:"The last file is the tmpl_env file.\nIt contains configuration variables for the individual services.\nThose variables can also be changed by the bash script dynamically, because the tmpl_env file is moved to the .env file in the same folder.\nWe use the configuration for example to dynamically set the IP Address of the host system or set the application version.\nTo use a variable in a docker-compose file just write it in braces, as shown below."}),"\n",(0,i.jsx)("img",{className:"blog-image",style:{maxWidth:"90%"},src:"/img/blog/2018-11-24/variables.png",alt:"How to use Environment Variables"}),"\n",(0,i.jsxs)(t.p,{children:["We hope this tool is helpful for your use case.\nWhen you have any problems, feedback, or ideas for improvements, contact us or open an issue on ",(0,i.jsx)(t.a,{href:"https://github.com/streampipes/container-cli",children:"GitHub"}),"."]})]})}function d(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},28453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var o=n(96540);const i={},a=o.createContext(i);function s(e){const t=o.useContext(a);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),o.createElement(a.Provider,{value:t},e.children)}},76503(e){e.exports=JSON.parse('{"permalink":"/blog/2018/11/24/container-cli","source":"@site/blog/2018-11-24-container-cli.md","title":"ContainerCLI: A CLI tool for your Docker Application","description":"6 minutes to read","date":"2018-11-24T00:00:00.000Z","tags":[],"readingTime":4.22,"hasTruncateMarker":true,"authors":[{"name":"Philipp Zehnder","url":"http://twitter.com/philipp10der","imageURL":"/img/zehnder.png","key":null,"page":null}],"frontMatter":{"title":"ContainerCLI: A CLI tool for your Docker Application","author":"Philipp Zehnder","authorURL":"http://twitter.com/philipp10der","authorImageURL":"/img/zehnder.png"},"unlisted":false,"prevItem":{"title":"StreamPipes release 0.61.0","permalink":"/blog/2019/04/04/release-0610"},"nextItem":{"title":"Preview: StreamPipes release 0.60.0","permalink":"/blog/2018/09/17/preview-060"}}')}}]);